static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    ConvStandard2dSquareInputAsymmetricKernelCustomTilingData tiling;

    // Shapes
    const auto *x_shape = context->GetInputShape(0);
    const auto *w_shape = context->GetInputShape(1);
    const uint32_t N = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(0));
    const uint32_t C = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(1));
    const uint32_t H = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(2));
    const uint32_t W = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(3));

    const uint32_t K  = static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(0));
    const uint32_t kH = static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(2));
    const uint32_t kW = static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(3));

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int32_t *stride_h = attrs->GetAttrPointer<int32_t>(0);
    const int32_t *stride_w = attrs->GetAttrPointer<int32_t>(1);
    const int32_t *pad_h    = attrs->GetAttrPointer<int32_t>(2);
    const int32_t *pad_w    = attrs->GetAttrPointer<int32_t>(3);
    const int32_t *dil_h    = attrs->GetAttrPointer<int32_t>(4);
    const int32_t *dil_w    = attrs->GetAttrPointer<int32_t>(5);
    const int32_t *groups   = attrs->GetAttrPointer<int32_t>(6);

    const uint32_t sH = static_cast<uint32_t>(*stride_h);
    const uint32_t sW = static_cast<uint32_t>(*stride_w);
    const uint32_t pH = static_cast<uint32_t>(*pad_h);
    const uint32_t pW = static_cast<uint32_t>(*pad_w);
    const uint32_t dH = static_cast<uint32_t>(*dil_h);
    const uint32_t dW = static_cast<uint32_t>(*dil_w);
    const uint32_t G  = static_cast<uint32_t>(*groups);

    // Assume standard conv: groups == 1
    // Output sizes (floor division)
    const uint32_t Ho = (H + 2U * pH - dH * (kH - 1U) - 1U) / sH + 1U;
    const uint32_t Wo = (W + 2U * pW - dW * (kW - 1U) - 1U) / sW + 1U;

    // Choose conservative tiling to fit UB budget.
    // UB estimate for maxima:
    //   inTile = C * ((tileH-1)*sH + 1 + (kH-1)*dH) * ((tileW-1)*sW + 1 + (kW-1)*dW)
    //   wTile  = tileK * C * kH * kW
    //   outTile= tileK * tileH * tileW
    // Choose small tiles to be safe.
    uint32_t tileH = 8;
    uint32_t tileW = 8;
    uint32_t tileK = 8;

    // Bound tiles by output dims
    tileH = MinU(tileH, Ho == 0U ? 1U : Ho);
    tileW = MinU(tileW, Wo == 0U ? 1U : Wo);
    tileK = MinU(tileK, K  == 0U ? 1U : K);

    const uint32_t tilesN = N;
    const uint32_t tilesH = CeilDiv(Ho, tileH);
    const uint32_t tilesW = CeilDiv(Wo, tileW);
    const uint32_t tilesK = CeilDiv(K, tileK);

    const uint32_t totalTiles = tilesN * tilesK * tilesH * tilesW;

    uint32_t blockDim = totalTiles;
    if (blockDim < 1U) blockDim = 1U;
    if (blockDim > 32U) blockDim = 32U;  // typical ceiling for 910B

    context->SetBlockDim(blockDim);

