    tiling.set_Wo(Wo);
    tiling.set_strideH(sH);
    tiling.set_strideW(sW);
    tiling.set_padH(pH);
    tiling.set_padW(pW);
    tiling.set_dilH(dH);
    tiling.set_dilW(dW);
    tiling.set_groups(G);
    tiling.set_tileH(tileH);
